function ModuleSubnavCard({ title, items, activeSection, onOpenSection, icon: Icon }) {
  return (
    <article className={`${panelClass} p-4`}>
      <div className="flex items-center gap-2 text-[14px] font-extrabold text-[#14853a]">
        <Icon className="size-4" />
        <span>{title}</span>
      </div>
      <div className="mt-4 space-y-1.5">
        {items.map((item) => {
          const isActive = activeSection === item;
          const label = getModuleSubnavLabel(item);
          return (
            <button
              key={item}
              type="button"
              onClick={() => onOpenSection(item)}
              className={cx('flex w-full items-center gap-3 rounded-[8px] px-3 py-3 text-left text-[13px] font-bold transition', isActive ? 'bg-[#eefbf1] text-[#078c3e]' : 'text-[#314a79] hover:bg-[#f8fbff]')}
            >
              <span className={cx('size-1.5 rounded-full', isActive ? 'bg-[#14b84c]' : 'bg-[#b9c4d6]')} />
              <span>{label}</span>
            </button>
          );
        })}
      </div>
    </article>
  );
}

function getModuleSubnavLabel(item) {
  if (item === 'O&M Overview') {
    return 'Overview';
  }

  if (item === 'Project Overview') {
    return 'Overview';
  }

  if (item === 'Project KPI Analytics') {
    return 'KPI Analytics';
  }

  if (item === 'Project Timeline') {
    return 'Timeline';
  }

  if (item === 'Project Site Survey') {
    return 'Site Survey';
  }

  if (item === 'Project Installation') {
    return 'Installation';
  }

  if (item === 'Project Team Assignment') {
    return 'Team Assignment';
  }

  if (item === 'Project Material Planning') {
    return 'Material Planning';
  }

  if (item === 'Project Work Orders') {
    return 'Work Orders';
  }

  if (item === 'Project Expenses') {
    return 'Expenses';
  }

  if (item === 'Project Documents') {
    return 'Documents';
  }

  if (item === 'Project Approvals') {
    return 'Approvals';
  }

  if (item === 'Project Reports') {
    return 'Reports';
  }

  if (item === 'O&M Reports') {
    return 'Reports';
  }

  if (item === 'AMC Documents') {
    return 'Documents';
  }

  return item;
}

function HorizontalModuleTabs({ title, helperText, items, activeSection, onOpenSection, activeClasses, activeDotClass, activeIconClass, wrapOnDesktop = false, compact = false, fullLabels = false }) {
  return (
    <section className={`${panelClass} overflow-hidden p-3 sm:p-4`}>
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <p className="font-display text-[16px] font-extrabold text-[#1e3261]">{title}</p>
          <p className="mt-1 text-[12px] font-bold text-[#6f7f98]">{helperText}</p>
        </div>
      </div>

      <div className="module-tab-scroll -mx-1 mt-4 overflow-x-auto px-1 pb-2">
        <div className={cx('flex w-max min-w-full gap-3', wrapOnDesktop && 'xl:min-w-0 xl:flex-wrap')}>
          {items.map((item) => {
            const isActive = activeSection === item;
            const label = fullLabels ? item : getModuleSubnavLabel(item);
            return (
              <button
                key={item}
                type="button"
                onClick={() => onOpenSection(item)}
                className={cx(
                  'module-tab-button inline-flex h-[54px] shrink-0 items-center justify-between gap-3 whitespace-nowrap rounded-[12px] border px-4 text-left shadow-[0_10px_20px_rgba(17,39,84,0.04)] transition hover:-translate-y-0.5',
                  compact ? 'min-w-[152px]' : 'min-w-[170px]',
                  fullLabels && 'min-w-max',
                  wrapOnDesktop && 'xl:min-w-[148px] xl:flex-1',
                  isActive ? activeClasses : 'border-[#d9e4f2] bg-white text-[#314a79] hover:border-[#c8d8ed] hover:bg-[#f8fbff]',
                )}
                title={label}
              >
                <span className="inline-flex min-w-0 items-center gap-3">
                  <span className={cx('size-2 rounded-full', isActive ? activeDotClass : 'bg-[#b9c4d6]')} />
                  <span className="text-[13px] font-extrabold">{label}</span>
                </span>
                <ChevronRight className={cx('size-4 shrink-0', isActive ? activeIconClass : 'text-[#9aa8bc]')} />
              </button>
            );
          })}
        </div>
      </div>
    </section>
  );
}

