                    {['#', 'Commissioning No.', 'Application No.', 'Project / Company', 'Application Type', 'Location', 'Commissioning Engineer', 'Scheduled Date', 'Status', 'Commissioned On', 'Actions'].map((header) => (
                      <th key={header}>{header}</th>
                    ))}
