    setTransfers((current) => (current.some((item) => item.id === nextTransfer.id) ? current.map((item) => (item.id === nextTransfer.id ? nextTransfer : item)) : [nextTransfer, ...current]));
    setModalType(null);
    onNotify(`${nextTransfer.transferNo} saved`);
